import{_ as r,o,c as l,ag as a}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"东京旅游攻略2026 | iVoyageWiki","description":"2026东京自由行完整攻略：交通、景点、美食、住宿一站式指南。含浅草寺、涩谷、迪士尼、秋叶原等必去景点详细规划。","frontmatter":{"title":"东京旅游攻略2026 | iVoyageWiki","description":"2026东京自由行完整攻略：交通、景点、美食、住宿一站式指南。含浅草寺、涩谷、迪士尼、秋叶原等必去景点详细规划。"},"headers":[],"relativePath":"destinations/亚洲/日本/东京.md","filePath":"destinations/亚洲/日本/东京.md","lastUpdated":null}'),i={name:"destinations/亚洲/日本/东京.md"};function n(s,t,e,g,d,h){return o(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="东京旅游攻略2026-第一次去东京必看指南" tabindex="-1">东京旅游攻略2026 | 第一次去东京必看指南 <a class="header-anchor" href="#东京旅游攻略2026-第一次去东京必看指南" aria-label="Permalink to &quot;东京旅游攻略2026 | 第一次去东京必看指南&quot;">​</a></h1><p>欢迎来到东京！这座将超现代与传统完美融合的城市，总有无尽的惊喜等待着你。这篇攻略持续更新至2026年，涵盖住宿、交通、景点、美食、购物、避坑等全方位信息，无论你是第一次来还是再次造访，都能找到实用内容。</p><p><img src="https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=800&amp;h=400&amp;fit=crop" alt="intro"></p><h2 id="📋-城市概览" tabindex="-1">📋 城市概览 <a class="header-anchor" href="#📋-城市概览" aria-label="Permalink to &quot;📋 城市概览&quot;">​</a></h2><ul><li><strong>建议旅行天数</strong>：3-7天。3天可走经典路线，5-7天可深度游或加入周边箱根/镰仓一日游</li><li><strong>最佳旅行时间</strong>：3月下旬-4月（樱花季）、10月-11月（红叶季）、12月（圣诞灯饰）。避开8月（酷暑潮湿）和元旦前后（许多店铺休业）</li><li><strong>消费水平</strong>：经济型（单人800-1200元/天，胶囊旅馆+便利店餐）、舒适型（1500-2500元/天，商务酒店+普通餐厅）、豪华型（3500元+/天，五星酒店+米其林）</li><li><strong>城市分区速览</strong>： <ul><li>🏯 <strong>浅草/上野（下町）</strong>：江户风情、浅草寺、晴空塔，传统氛围浓厚</li><li>🚀 <strong>秋叶原</strong>：电器街、动漫文化圣地，御宅族天堂</li><li>👗 <strong>涩谷/原宿/表参道</strong>：潮流发源地、年轻文化中心</li><li>💎 <strong>银座/丸之内</strong>：高端购物、顶级餐饮、奢华体验</li><li>🌃 <strong>新宿</strong>：娱乐不夜城、美食激战区、东京都厅免费夜景</li><li>🌸 <strong>六本木/赤坂</strong>：艺术馆、高层夜景、夜生活</li></ul></li><li><strong>语言与货币</strong>：日语为主要语言，旅游业者有一定英语基础。货币为日元（JPY），目前汇率约100日元≈4.8元人民币。大部分商家支持IC卡（Suica/PASMO）和信用卡</li></ul><h2 id="📅-行程规划" tabindex="-1">📅 行程规划 <a class="header-anchor" href="#📅-行程规划" aria-label="Permalink to &quot;📅 行程规划&quot;">​</a></h2><h3 id="_3天经典行程-第一次来东京首选" tabindex="-1">3天经典行程（第一次来东京首选） <a class="header-anchor" href="#_3天经典行程-第一次来东京首选" aria-label="Permalink to &quot;3天经典行程（第一次来东京首选）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>上午</th><th>下午</th><th>晚上</th></tr></thead><tbody><tr><td><strong>Day 1</strong></td><td>浅草寺 → 仲见世商店街</td><td>东京晴空塔（含墨田水族馆）</td><td>秋叶原电器街+动漫扫货</td></tr><tr><td><strong>Day 2</strong></td><td>明治神宫 → 原宿竹下通</td><td>涩谷十字路口+涩谷SKY展望台</td><td>新宿思出横丁+歌舞伎町（仅外观）</td></tr><tr><td><strong>Day 3</strong></td><td>东京迪士尼乐园（全天）或 箱根一日游</td><td>—</td><td>台场海滨公园+高达像/大江户温泉物语</td></tr></tbody></table><h3 id="_5天深度行程" tabindex="-1">5天深度行程 <a class="header-anchor" href="#_5天深度行程" aria-label="Permalink to &quot;5天深度行程&quot;">​</a></h3><ul><li><strong>Day 1</strong>：浅草寺 → 晴空塔 → 两国国技馆（相扑博物馆）→ 秋叶原</li><li><strong>Day 2</strong>：皇居东御苑 → 东京站一番街 → 银座 → 筑地场外市场（午餐）</li><li><strong>Day 3</strong>：明治神宫 → 原宿竹下通 → 表参道 → 涩谷 → 惠比寿</li><li><strong>Day 4</strong>：上野公园 → 东京国立博物馆 → 阿美横丁 → 日暮里纤维街</li><li><strong>Day 5</strong>：新宿御苑 → 东京都厅免费展望台 → 下北泽古着探店 → 新宿晚餐</li></ul><h3 id="_7天全面行程" tabindex="-1">7天全面行程 <a class="header-anchor" href="#_7天全面行程" aria-label="Permalink to &quot;7天全面行程&quot;">​</a></h3><ul><li><strong>Day 1-3</strong>：同上3天经典行程</li><li><strong>Day 4</strong>：镰仓一日游（镰仓大佛+鹤冈八幡宫+江之岛+灌篮高手平交道）</li><li><strong>Day 5</strong>：三鹰之森吉卜力美术馆 → 吉祥寺（商店街+井之头公园）</li><li><strong>Day 6</strong>：台场（高达像+丰田汽车馆+Palette Town摩天轮+大江户温泉）</li><li><strong>Day 7</strong>：自由安排/补货购物（推荐去涩谷或银座扫尾）</li></ul><h3 id="_2026年新增-升级景点" tabindex="-1">2026年新增/升级景点 <a class="header-anchor" href="#_2026年新增-升级景点" aria-label="Permalink to &quot;2026年新增/升级景点&quot;">​</a></h3><ul><li><strong>丰洲teamLab Planets</strong>：2025年起扩建新展区，2026年全面开放，沉浸式数字艺术体验</li><li><strong>东京迪士尼海洋全新园区「Fantasy Springs」</strong>：2024年开幕，含《冰雪奇缘》《魔发奇缘》《彼得潘》主题区</li><li><strong>麻布台Hills</strong>：2023年开幕的综合设施，33层免费展望台可同时看到东京塔和富士山</li><li><strong>TOKYO TORCH</strong>：常盘桥再开发项目，2026年部分开放</li></ul><h2 id="✈️-行前准备" tabindex="-1">✈️ 行前准备 <a class="header-anchor" href="#✈️-行前准备" aria-label="Permalink to &quot;✈️ 行前准备&quot;">​</a></h2><h3 id="证件准备" tabindex="-1">证件准备 <a class="header-anchor" href="#证件准备" aria-label="Permalink to &quot;证件准备&quot;">​</a></h3><ul><li>护照（有效期需超过6个月）</li><li>日本签证：中国公民需提前办理旅游签证，目前单次/三年多次/五年多次可选。2025年起部分国家开放电子签（JESTA），中国尚未列入，请持续关注</li><li>建议复印护照首页和签证页随身携带</li></ul><h3 id="住宿推荐" tabindex="-1">住宿推荐 <a class="header-anchor" href="#住宿推荐" aria-label="Permalink to &quot;住宿推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>优点</th><th>缺点</th><th>适合人群</th></tr></thead><tbody><tr><td><strong>新宿</strong></td><td>交通枢纽(多条JR/地铁)、美食选择多、夜生活丰富</td><td>人流量大、部分区域入夜后较杂</td><td>第一次来、交通便利优先</td></tr><tr><td><strong>涩谷</strong></td><td>年轻人潮流中心、交通方便、餐厅多</td><td>住宿价格偏高、早晚人流密集</td><td>年轻游客、购物为主</td></tr><tr><td><strong>上野/浅草</strong></td><td>住宿便宜、传统氛围、成田机场直达</td><td>距新宿涩谷较远约20分钟</td><td>预算有限、家庭游客</td></tr><tr><td><strong>银座/东京站</strong></td><td>高端酒店集中、交通极其便利、治安好</td><td>价格天花板</td><td>商务出行、预算充足</td></tr><tr><td><strong>池袋</strong></td><td>住宿性价比高、中国餐厅多、交通方便</td><td>距离部分景点较远</td><td>预算有限、长住游客</td></tr></tbody></table><h3 id="行李清单" tabindex="-1">行李清单 <a class="header-anchor" href="#行李清单" aria-label="Permalink to &quot;行李清单&quot;">​</a></h3><ul><li><strong>必备</strong>：护照、签证、机票行程单、酒店预订单、保险单、日元现金（建议3-5万日元）</li><li><strong>衣物</strong>：根据季节准备，东京四季分明。夏季轻薄透气，冬季需厚外套。舒适的步行鞋非常重要！</li><li><strong>数码</strong>：充电宝（日本共享充电宝较少）、转换插头（日本为两脚扁插头，国内两脚可用）、数据线</li><li><strong>生活</strong>：折叠伞（东京天气多变）、环保袋（购物使用）、口罩（流感季建议）</li><li><strong>药品</strong>：感冒药、肠胃药（饮食不适应）、创可贴</li></ul><h3 id="网络与通讯" tabindex="-1">网络与通讯 <a class="header-anchor" href="#网络与通讯" aria-label="Permalink to &quot;网络与通讯&quot;">​</a></h3><ul><li><strong>eSIM</strong>：最推荐方式，出发前购买，到达后激活。Airalo、Nomad等平台有日本套餐，7天10GB约40-60元</li><li><strong>随身WiFi</strong>：可在国内提前租借（约10-15元/天），在机场取还。适合多人共享</li><li><strong>日本SIM卡</strong>：可在机场或Bic Camera购买，需出示护照。推荐IIJmio或乐天Mobile</li></ul><h3 id="必备app推荐" tabindex="-1">必备APP推荐 <a class="header-anchor" href="#必备app推荐" aria-label="Permalink to &quot;必备APP推荐&quot;">​</a></h3><ul><li><strong>Google Maps</strong>：东京交通导航首选，精确显示列车时刻、出口编号、月台信息</li><li><strong>JapanTravel by NAVITIME</strong>：日本专业交通规划，比Google Maps更精确的新干线/私铁规划</li><li><strong>乘換案内</strong>：日本人最常用的交通APP，日文界面但汉字多可猜</li><li><strong>食べログ (Tabelog)</strong>：日本版大众点评，3.5分以上基本不踩雷</li><li><strong>DeepL</strong>：日文翻译比Google准确，支持拍照翻译</li><li><strong>Suica/PASMO</strong>：可添加到Apple Wallet中，手机直接刷进站</li><li><strong>Disney Resort APP</strong>：迪士尼排队时间查询、预约热门项目</li></ul><h3 id="景点预约信息" tabindex="-1">景点预约信息 <a class="header-anchor" href="#景点预约信息" aria-label="Permalink to &quot;景点预约信息&quot;">​</a></h3><ul><li><strong>三鹰之森吉卜力美术馆</strong>：每月10日开放下月门票，需提前在Lawson购买，非常抢手</li><li><strong>迪士尼乐园/海洋</strong>：建议提前1-2个月购票，旺季可能售罄</li><li><strong>teamLab Planets / teamLab Borderless</strong>：需提前在官网预约时段</li><li><strong>东京晴空塔</strong>：建议提前在Klook或官网购买快速通行票</li><li><strong>Shibuya SKY展望台</strong>：需提前2周预约日落时段，非常热门</li></ul><h2 id="🚇-交通指南" tabindex="-1">🚇 交通指南 <a class="header-anchor" href="#🚇-交通指南" aria-label="Permalink to &quot;🚇 交通指南&quot;">​</a></h2><h3 id="机场到市区" tabindex="-1">机场到市区 <a class="header-anchor" href="#机场到市区" aria-label="Permalink to &quot;机场到市区&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>时间</th><th>价格（成人）</th><th>备注</th></tr></thead><tbody><tr><td><strong>N&#39;EX成田特快</strong>（成田）</td><td>约60分到东京站</td><td>约3000日元</td><td>舒适直达，有往返优惠票</td></tr><tr><td><strong>京成Skyliner</strong>（成田）</td><td>约41分到日暮里</td><td>约2500日元</td><td>最快到上野/日暮里</td></tr><tr><td><strong>京成Access特急</strong>（成田）</td><td>约60-80分</td><td>约1300日元</td><td>便宜但停站多</td></tr><tr><td><strong>机场大巴</strong>（成田/羽田）</td><td>约60-90分</td><td>约1300-3100日元</td><td>有行李直放，到新宿/银座等</td></tr><tr><td><strong>东京单轨电车</strong>（羽田）</td><td>约15分到滨松町</td><td>约500日元</td><td>羽田出发最快方式</td></tr><tr><td><strong>京急空港线</strong>（羽田）</td><td>约20分到品川</td><td>约300日元</td><td>便宜且到品川转乘方便</td></tr><tr><td><strong>出租车</strong></td><td>约60-90分</td><td>约20000-30000日元</td><td>多人/行李多可考虑</td></tr></tbody></table><h3 id="市内交通" tabindex="-1">市内交通 <a class="header-anchor" href="#市内交通" aria-label="Permalink to &quot;市内交通&quot;">​</a></h3><p><strong>地铁系统</strong> 东京的轨道交通由多家公司运营，构成极其复杂的网络：</p><ul><li><strong>东京地铁</strong>（Tokyo Metro）：9条线路，覆盖市中心主要区域</li><li><strong>都营地铁</strong>（Toei Subway）：4条线路（浅草线、三田线、新宿线、大江户线），通往更多区域</li><li><strong>JR东日本</strong>：山手线（环状线最常用）、中央线、总武线等</li><li><strong>私铁</strong>：东急、小田急、京王、西武等通往郊区</li></ul><p><strong>推荐交通票券</strong></p><ul><li><strong>东京地铁24/48/72小时通票</strong>：800/1200/1500日元，无限乘坐东京地铁和都营地铁，超值！</li><li><strong>JR东京广域周游券</strong>：10180日元/3天，适合去富士山、轻井泽、日光等周边</li><li><strong>Suica / PASMO</strong>：IC卡，充值后刷卡乘车，也可在便利店购物。Apple Wallet可直接添加</li><li><strong>Tokyo Subway Ticket + 机场套票</strong>：成田/羽田机场有售，含机场到市区+地铁通票</li></ul><p><strong>其他出行方式</strong></p><ul><li><strong>公交车</strong>：线路复杂不推荐游客使用，但某些景点（如东京塔附近）可到达</li><li><strong>出租车</strong>：起步价约420-500日元，深夜加价20%。不堵车时3-4人拼车可能比地铁划算</li><li><strong>自行车</strong>：部分区域有共享单车（Hello Cycling等），适合下町区域探索</li></ul><h3 id="交通卡购买指南" tabindex="-1">交通卡购买指南 <a class="header-anchor" href="#交通卡购买指南" aria-label="Permalink to &quot;交通卡购买指南&quot;">​</a></h3><ol><li><strong>Suica</strong>：JR东日本发行，可在JR车站的售票机购买，押金500日元</li><li><strong>PASMO</strong>：东京地铁发行，功能和Suica完全相同</li><li><strong>Welcome Suica</strong>：专为游客设计的无押金版，有效期28天，可在成田/羽田机场购买</li><li><strong>手机添加</strong>：iPhone用户可直接在Wallet中添加Suica/PASMO，用银联/Visa充值，极其方便</li></ol><h2 id="🏛️-景点打卡" tabindex="-1">🏛️ 景点打卡 <a class="header-anchor" href="#🏛️-景点打卡" aria-label="Permalink to &quot;🏛️ 景点打卡&quot;">​</a></h2><h3 id="浅草·上野-下町风情区" tabindex="-1">浅草·上野（下町风情区） <a class="header-anchor" href="#浅草·上野-下町风情区" aria-label="Permalink to &quot;浅草·上野（下町风情区）&quot;">​</a></h3><p><strong>浅草寺</strong>（Senso-ji）</p><ul><li>东京最古老的寺庙，建于628年。穿过巨大的雷门灯笼，走过300米长的仲见世商店街，抵达宝藏门和本堂</li><li><strong>门票</strong>：免费</li><li><strong>开放时间</strong>：本堂6:00-17:00（10月-3月至17:30）</li><li><strong>Tips</strong>：建议8:00前到达避开人潮；仲见世商店街9:00后才全开，可先参拜再购物；雷门和五重塔是最佳拍照点</li><li><strong>交通</strong>：东京地铁浅草站</li></ul><p><img src="https://images.unsplash.com/photo-1536097326-f2a6c9f6b4f0?w=800&amp;h=400&amp;fit=crop" alt="浅草寺"></p><p><strong>东京晴空塔</strong>（Tokyo Skytree）</p><ul><li>高634米的全球最高电波塔，展望台分为350米的Tembo Deck和450米的Tembo Galleria</li><li><strong>门票</strong>：2100日元（Tembo Deck）/ 3100日元（Tembo Galleria），Klook提前购约9折</li><li><strong>开放时间</strong>：10:00-21:00（最终入场20:00）</li><li><strong>Tips</strong>：日落前1小时入场可看到日夜转换；晴空街道Solamachi有300+店铺和墨田水族馆；2楼有直达巴士去台场</li><li><strong>交通</strong>：东武晴空塔线东京晴空塔站</li></ul><p><strong>上野公园&amp;东京国立博物馆</strong></p><ul><li>上野公园是东京的文化中心，内有东京国立博物馆、国立科学博物馆、国立西洋美术馆和上野动物园</li><li><strong>门票</strong>：公园免费；博物馆各馆单独售票，国立博物馆1000日元</li><li><strong>Tips</strong>：樱花季的上野公园是东京最著名的赏樱地之一；每月第2、第4个周六国立博物馆对高中生以下免费</li></ul><h3 id="涩谷·原宿-潮流中心区" tabindex="-1">涩谷·原宿（潮流中心区） <a class="header-anchor" href="#涩谷·原宿-潮流中心区" aria-label="Permalink to &quot;涩谷·原宿（潮流中心区）&quot;">​</a></h3><p><strong>涩谷十字路口</strong>（Shibuya Crossing）</p><ul><li>世界最繁忙的十字路口，一次绿灯最多有3000人同时通过</li><li><strong>最佳观赏点</strong>：二楼星巴克（需排队）、涩谷全向十字路口旁的Tsutaya Starbucks、涩谷SKY展望台俯拍</li><li><strong>免费</strong>：观赏无需费用</li></ul><p><strong>涩谷SKY</strong>（Shibuya Sky）</p><ul><li>涩谷Scramble Square顶层的大型露天展望台，360度无遮挡视野</li><li><strong>门票</strong>：2000日元（需提前预约指定时段）</li><li><strong>Tips</strong>：日落时段（约16:00-17:00）最热门，建议提前2周预约；屋顶露天部分有发光地板和吊床</li></ul><p><strong>明治神宫</strong>（Meiji Jingu）</p><ul><li>供奉明治天皇和昭宪皇太后的神社，东京最重要的神社之一。参道两侧的樟树林荫道令人心旷神怡</li><li><strong>门票</strong>：免费（本殿参观免费，宝物殿500日元）</li><li><strong>开放时间</strong>：日出至日落（约6:00-16:00随季节变化）</li><li><strong>Tips</strong>：新年参拜人数居日本第一；可以体验求御朱印（300日元）；原宿口出来就是竹下通</li></ul><p><strong>原宿竹下通</strong></p><ul><li>原宿最具代表性的步行街，集中了可丽饼店、潮流服饰店、古着店和杂货店</li><li><strong>Tips</strong>：周末人山人海，建议平日前往；竹下通可丽饼是必吃（约400-600日元）；推荐逛We GO和Chicago古着店</li></ul><h3 id="新宿·歌舞伎町-娱乐不夜城" tabindex="-1">新宿·歌舞伎町（娱乐不夜城） <a class="header-anchor" href="#新宿·歌舞伎町-娱乐不夜城" aria-label="Permalink to &quot;新宿·歌舞伎町（娱乐不夜城）&quot;">​</a></h3><p><strong>新宿御苑</strong></p><ul><li>融合日式、法式和英式三种园林风格的城市绿洲，新海诚《言叶之庭》取景地</li><li><strong>门票</strong>：500日元</li><li><strong>开放时间</strong>：9:00-17:00（周一休园，3月底-4月樱花季无休）</li><li><strong>Tips</strong>：樱花季约3月底-4月初，有约65种樱花；枫叶季11月也极美；禁止携带三脚架</li></ul><p><strong>东京都厅展望室</strong>（免费夜景）</p><ul><li>202米高的免费展望台，能看到富士山（天气好时）和东京全景</li><li><strong>门票</strong>：免费！</li><li><strong>开放时间</strong>：9:30-22:00（北展望室）；南展望室至17:00</li><li><strong>Tips</strong>：位于新宿西口步行10分钟，是性价比最高的夜景选择；咖啡馆座位有限</li></ul><p><img src="https://images.unsplash.com/photo-1551641506-1205c4f8b0f6?w=800&amp;h=400&amp;fit=crop" alt="东京夜景"></p><h3 id="银座·丸之内-高端购物区" tabindex="-1">银座·丸之内（高端购物区） <a class="header-anchor" href="#银座·丸之内-高端购物区" aria-label="Permalink to &quot;银座·丸之内（高端购物区）&quot;">​</a></h3><p><strong>银座</strong>（Ginza）</p><ul><li>东京最有代表性的高端商业区，集中了LV、Chanel、Hermès等旗舰店，以及松屋、三越等百货</li><li><strong>Tips</strong>：周末步行者天国（中央通禁止车辆通行）；推荐逛银座六号（Ginza Six）和东急PLAZA银座；UNIQLO银座旗舰店有东京限定款</li></ul><p><strong>筑地场外市场</strong></p><ul><li>虽然场内市场已搬迁至丰洲，但场外市场依然保留着300+家店铺，是东京的厨房</li><li><strong>Tips</strong>：推荐寿司大、大和寿司（需排队1-2小时）；玉子烧（500日元/串）、烤海鲜、抹茶冰淇淋边走边吃；建议9:00前到达避开旅游团</li></ul><h3 id="秋叶原-御宅文化圣地" tabindex="-1">秋叶原（御宅文化圣地） <a class="header-anchor" href="#秋叶原-御宅文化圣地" aria-label="Permalink to &quot;秋叶原（御宅文化圣地）&quot;">​</a></h3><p><strong>秋叶原电器街</strong></p><ul><li>全球著名的电器和动漫文化中心，汇聚了友都八喜（Yodobashi Camera）、Bic Camera等电器店和Animate、虎穴等动漫店</li><li><strong>Tips</strong>：免税购物记得带护照；友都八喜买电器可享10%免税+7%信用卡折扣；Radio会馆是动漫手办圣地；女仆咖啡厅体验约2000-3000日元</li></ul><h3 id="迪士尼度假区" tabindex="-1">迪士尼度假区 <a class="header-anchor" href="#迪士尼度假区" aria-label="Permalink to &quot;迪士尼度假区&quot;">​</a></h3><p><strong>东京迪士尼乐园 &amp; 迪士尼海洋</strong></p><ul><li>亚洲第一座迪士尼乐园，迪士尼海洋是全球唯一以海洋为主题的迪士尼</li><li><strong>门票</strong>：一日券7900-9400日元（浮动票价），建议Klook提前购买</li><li><strong>Tips</strong>：下载Tokyo Disney Resort APP预约热门项目的DPA（Disney Premier Access）；避免周末和日本节假日；海洋的「翱翔：梦幻奇航」和「玩具总动员疯狂游戏屋」最热门；2024年新开Fantasy Springs主题区需单独预约</li></ul><h2 id="🍜-美食推荐" tabindex="-1">🍜 美食推荐 <a class="header-anchor" href="#🍜-美食推荐" aria-label="Permalink to &quot;🍜 美食推荐&quot;">​</a></h2><h3 id="必吃菜推荐" tabindex="-1">必吃菜推荐 <a class="header-anchor" href="#必吃菜推荐" aria-label="Permalink to &quot;必吃菜推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th>菜品</th><th>人均预算</th><th>推荐餐厅</th></tr></thead><tbody><tr><td><strong>寿司</strong></td><td>3000-10000日元</td><td>数寄屋桥次郎（银座，米其林三星，需提前1月预约）、美登利（涩谷，高性价比回转寿司）、筑地寿司大</td></tr><tr><td><strong>拉面</strong></td><td>800-1500日元</td><td>一兰（全球连锁，个人隔间体验）、麵屋武藏（新宿，浓厚豚骨鱼介）、AFURI（柚子盐拉面，清爽系代表）</td></tr><tr><td><strong>天妇罗</strong></td><td>2000-10000日元</td><td>美川（浅草，米其林一星，需预约）、Tempura Tsunahachi（新宿，性价比高）</td></tr><tr><td><strong>和牛/烧肉</strong></td><td>5000-15000日元</td><td>叙叙苑（连锁，午市套餐3500起超值）、USHIGORO S.（银座，顶级和牛，需预约）</td></tr><tr><td><strong>鳗鱼饭</strong></td><td>3000-8000日元</td><td>野田岩（麻布，180年老店，米其林一星）、伊豆荣（上野，蒲烧鳗鱼老铺）</td></tr><tr><td><strong>蛋包饭</strong></td><td>1000-2000日元</td><td>喫茶YOU（银座，昭和风蛋包饭）、キッチンジロー（表参道）</td></tr><tr><td><strong>文字烧/御好烧</strong></td><td>1500-2500日元</td><td>月岛文字烧一条街、千房（大阪烧连锁）</td></tr></tbody></table><p><img src="https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=800&amp;h=400&amp;fit=crop" alt="东京美食"></p><h3 id="特色小吃-美食街" tabindex="-1">特色小吃/美食街 <a class="header-anchor" href="#特色小吃-美食街" aria-label="Permalink to &quot;特色小吃/美食街&quot;">​</a></h3><ul><li><strong>筑地场外市场</strong>：海鲜丼、玉子烧、烤海鲜、草莓大福</li><li><strong>阿美横丁</strong>：上野站旁，平价小吃和海鲜摊，适合边走边吃</li><li><strong>思出横丁</strong>：新宿西口小巷，昭和风居酒屋一条街，适合喝酒吃串烧</li><li><strong>月岛文字烧一条街</strong>：东京特色文字烧，自己动手煎</li><li><strong>原宿竹下通可丽饼</strong>：Marion Crepes和Angels Heart最有名</li></ul><h3 id="避坑指南" tabindex="-1">避坑指南 <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;避坑指南&quot;">​</a></h3><ul><li>米其林餐厅务必提前预约，直接到店基本吃不到</li><li>部分拉面店使用食券机，先在门外机器买券再入座</li><li>居酒屋可能有「お通し」（座位费）约300-500日元，是惯例非欺诈</li><li>东京餐厅禁止自带饮料食物入内</li><li>边走边吃在日本会被视为不礼貌（竹下通可丽饼例外）</li></ul><h2 id="🎡-特色体验" tabindex="-1">🎡 特色体验 <a class="header-anchor" href="#🎡-特色体验" aria-label="Permalink to &quot;🎡 特色体验&quot;">​</a></h2><h3 id="本地特色活动" tabindex="-1">本地特色活动 <a class="header-anchor" href="#本地特色活动" aria-label="Permalink to &quot;本地特色活动&quot;">​</a></h3><ul><li><strong>樱花季赏花</strong>（3-4月）：上野公园、新宿御苑、目黑川沿岸，当地人会铺蓝布喝酒野餐</li><li><strong>花火大会</strong>（7-8月）：隅田川花火大会、神宫外苑花火大会等，穿着浴衣参加</li><li><strong>浅草三社祭</strong>（5月）：江户三大祭之一，抬神轿游行</li><li><strong>新年参拜</strong>（1月1日）：明治神宫新年参拜，体验日本新年文化</li><li><strong>相扑观战</strong>（1/5/9月）：两国国技馆，需提前购票</li></ul><h3 id="夜生活" tabindex="-1">夜生活 <a class="header-anchor" href="#夜生活" aria-label="Permalink to &quot;夜生活&quot;">​</a></h3><ul><li><strong>黄金街</strong>（新宿）：数百家迷你酒吧和居酒屋，文艺气息浓厚</li><li><strong>六本木</strong>：夜店和酒吧集中区，外国人较多</li><li><strong>涩谷中心街</strong>：年轻人夜生活中心，居酒屋和酒吧林立</li><li><strong>惠比寿/代官山</strong>：成人向的高品质酒吧和餐厅</li></ul><h3 id="文化演出" tabindex="-1">文化演出 <a class="header-anchor" href="#文化演出" aria-label="Permalink to &quot;文化演出&quot;">​</a></h3><ul><li><strong>歌舞伎座</strong>（银座）：日本传统歌舞伎表演，有单幕票（约2000日元起），提供英文耳机导览</li><li><strong>TeamLab Planets / Borderless</strong>：沉浸式数字艺术，2024年Borderless移师麻布台Hills</li><li><strong>吉卜力美术馆</strong>：宫崎骏动画世界，需提前购票</li></ul><h2 id="🛍️-购物指南" tabindex="-1">🛍️ 购物指南 <a class="header-anchor" href="#🛍️-购物指南" aria-label="Permalink to &quot;🛍️ 购物指南&quot;">​</a></h2><h3 id="主要商圈" tabindex="-1">主要商圈 <a class="header-anchor" href="#主要商圈" aria-label="Permalink to &quot;主要商圈&quot;">​</a></h3><table tabindex="0"><thead><tr><th>商圈</th><th>风格</th><th>必逛店铺</th><th>适合买什么</th></tr></thead><tbody><tr><td><strong>银座</strong></td><td>高端奢华</td><td>Ginza Six、松屋、三越、LV旗舰店</td><td>奢侈品、高级化妆品</td></tr><tr><td><strong>涩谷</strong></td><td>年轻潮流</td><td>涩谷109、Loft、Parco、MEGA唐吉诃德</td><td>潮牌、美妆、杂货</td></tr><tr><td><strong>新宿</strong></td><td>综合大型</td><td>伊势丹、Lumine Est、BicQlo</td><td>百货、电器、药妆</td></tr><tr><td><strong>原宿/表参道</strong></td><td>时尚设计</td><td>Laforet、表参道Hills、Supreme</td><td>设计师品牌、古着</td></tr><tr><td><strong>秋叶原</strong></td><td>电器动漫</td><td>友都八喜、Bic Camera、Radio会馆</td><td>电器、动漫周边、手办</td></tr><tr><td><strong>台场</strong></td><td>家庭休闲</td><td>DiverCity Tokyo、VenusFort</td><td>奥特莱斯、娱乐</td></tr></tbody></table><h3 id="伴手礼推荐" tabindex="-1">伴手礼推荐 <a class="header-anchor" href="#伴手礼推荐" aria-label="Permalink to &quot;伴手礼推荐&quot;">​</a></h3><ul><li><strong>东京香蕉</strong>（Tokyo Banana）：经典蛋糕，约1000日元/盒，机场和东京站有售</li><li><strong>白色恋人</strong>：北海道名产但东京也买得到，机场免税店</li><li><strong>抹茶甜点</strong>：抹茶KitKat、抹茶巧克力（东京限定款）</li><li><strong>药妆</strong>：SK-II、资生堂、Anessa防晒、小林制药系列（比国内便宜30-50%）</li><li><strong>日本制刀具</strong>：合羽桥道具街有专业厨刀，2000-20000日元不等</li><li><strong>日式手帕（手拭い）</strong>：中川政七商店等有精美手帕，500-2000日元</li></ul><h2 id="⚠️-避坑指南" tabindex="-1">⚠️ 避坑指南 <a class="header-anchor" href="#⚠️-避坑指南" aria-label="Permalink to &quot;⚠️ 避坑指南&quot;">​</a></h2><h3 id="常见陷阱" tabindex="-1">常见陷阱 <a class="header-anchor" href="#常见陷阱" aria-label="Permalink to &quot;常见陷阱&quot;">​</a></h3><ol><li><strong>出租车&quot;入门料金&quot;</strong>：东京出租车起步价高，短途不如地铁</li><li><strong>餐厅隐藏费用</strong>：居酒屋的「お通し」（小菜费）约300-500日元是惯例</li><li><strong>浅草人力车夫</strong>：价格透明但体验时间短，拍照前先问价</li><li><strong>新宿歌舞伎町拉客</strong>：牛郎/女公关店拉客非常激进，不要跟陌生人走</li><li><strong>秋叶原路边电子产品</strong>：切勿购买路边兜售的&quot;超便宜&quot;电子产品，可能是假货或赃物</li><li><strong>兑换所汇率差</strong>：不要在国内/机场换太多，ATM取现汇率最优（7-11/三井住友ATM）</li><li><strong>寺庙签文</strong>：抽到凶签系在指定绳子上即可，不要塞进口袋带回家</li></ol><h3 id="安全注意事项" tabindex="-1">安全注意事项 <a class="header-anchor" href="#安全注意事项" aria-label="Permalink to &quot;安全注意事项&quot;">​</a></h3><ul><li>东京是世界上最安全的城市之一，但仍需注意保管随身物品</li><li>女性夜间出行建议避开新宿歌舞伎町和六本木的偏僻小巷</li><li>地铁高峰期（7:30-9:00、17:30-19:30）极为拥挤，女性专用车厢在首尾车厢</li><li>地震发生时保持冷静，遵循工作人员指示</li><li>台风季节（8-10月）关注天气预报，JR可能会停运</li></ul><h3 id="紧急联系方式" tabindex="-1">紧急联系方式 <a class="header-anchor" href="#紧急联系方式" aria-label="Permalink to &quot;紧急联系方式&quot;">​</a></h3><ul><li><strong>警察局</strong>：110</li><li><strong>消防/急救</strong>：119</li><li><strong>东京急救翻译中心</strong>：03-5285-8181（24小时，中英文对应）</li><li><strong>中国驻日本大使馆</strong>：03-3403-3388（港区麻布）</li><li><strong>日本旅游咨询中心</strong>：03-3201-3331（东京旅游信息中心，新宿）</li><li><strong>遗失物品</strong>：JR东日本遗失物品中心 03-3231-1880 / 东京地铁 03-3834-6666</li></ul><h2 id="❓-常见问题faq" tabindex="-1">❓ 常见问题FAQ <a class="header-anchor" href="#❓-常见问题faq" aria-label="Permalink to &quot;❓ 常见问题FAQ&quot;">​</a></h2><p><strong>Q：去东京需要给小费吗？</strong> A：不需要！日本没有小费文化，给予小费反而可能让对方困扰。服务费已包含在账单中。</p><p><strong>Q：东京的最佳季节是？</strong> A：3月底-4月（樱花季）和10月-11月（红叶+秋高气爽）是最佳季节。夏季炎热潮湿，冬季干冷但晴朗。</p><p><strong>Q：Suica和PASMO有什么区别？</strong> A：功能完全一样。Suica是JR发行，PASMO是东京地铁发行。乘车优惠完全相同，互相通用。推荐Welcome Suica（无押金，有效期28天）或iPhone Wallet直接添加。</p><p><strong>Q：东京迪士尼需要提前多久买票？</strong> A：建议提前1-2个月。旺季可能提前售罄，且工作日比周末便宜。门票采用动态定价。</p><p><strong>Q：不会日语能玩东京吗？</strong> A：完全可以。主要景点的指示牌有英文（部分有中文），地铁站内有英文播报。建议下载Google Maps和DeepL翻译APP。</p><p><strong>Q：抽到凶签怎么办？</strong> A：在日本神社抽到凶签是正常的，将其系在神社指定的绳子上即可化解，不要带回家。</p><p><strong>Q：东京住哪里最方便？</strong> A：第一次来推荐住<strong>新宿</strong>或<strong>涩谷</strong>附近，交通最便利。预算有限推荐<strong>上野</strong>。商务出行推荐<strong>东京站/银座</strong>。</p><p><strong>Q：东京购物能退税吗？</strong> A：可以。在贴有「Tax Free」标志的店铺消费满5000日元（不含税）即可退税，直接扣除消费税（10%）。食品和化妆品也可退税。记得携带护照。</p>',110)])])}const b=r(i,[["render",n]]);export{c as __pageData,b as default};
